function Cut(num, callback) {
  var numFinished = 0;
  return function () {
    numFinished++;
    if (numFinished === num) callback();
  };
}

var log = [];
var done = Cut(2, function () { log.push('both done'); });
log.push('before A');
done();
log.push('before B');
done();
console.log(log.join(', '));

