function Cut(num, callback) {
  var numFinished = 0;
  var results = {};
  return function (key, value) {
    results[key] = value;
    numFinished++;
    if (numFinished === num) callback(results);
  };
}

var onDone = Cut(2, function (results) {
  console.log('total:', results.cost + results.shipping);
});

// 模擬 shipping 先回來，cost 後回來
setTimeout(function () { onDone('shipping', 5); }, 5);
setTimeout(function () { onDone('cost', 20); }, 15);

