function JustOnce(action) {
  var alreadyCalled = false;
  return function (...args) {
    if (!alreadyCalled) {
      alreadyCalled = true;
      return action(...args);
    }
  };
}

var log = [];
var submitOnce = JustOnce(function (name) { log.push('submit ' + name); });
submitOnce('order1');
submitOnce('order1');
submitOnce('order1');
console.log(log.join(', '));

